// Validate secret and parse Zou event
const data = $input.first().json;
const expectedSecret = $env.N8N_WEBHOOK_HMAC_SECRET;

if (!expectedSecret) throw new Error('N8N_WEBHOOK_HMAC_SECRET not configured');

const headers = data.headers || {};
const body    = data.body    || data || {};
const receivedSecret = headers['x-webhook-secret'] || body.secret || '';

if (receivedSecret !== expectedSecret) throw new Error('Invalid webhook secret');

const event_type = body.event_type || body.type || 'unknown';
const event_data = body.data || {};

return [{ json: { event_type, data: event_data } }];

// Handle task:status-changed event from Kitsu
// Sync the status change back to NocoDB content record
const { event_type, data } = $input.first().json;

const task_id            = data.task_id            || data.id;
const new_task_status_id = data.new_task_status_id || data.task_status_id;
const entity_id          = data.entity_id          || data.shot_id;
const entity_name        = data.entity_name        || data.name;

// Use entity_name as content_id (Kitsu shot name = content_id)
const content_id = entity_name || entity_id;

if (content_id) {
  try {
    await $http.request({
      method: 'POST',
      url: 'http://localhost:5678/webhook/cf-update-content',
      headers: {
        'Content-Type': 'application/json',
        'x-webhook-secret': $env.N8N_WEBHOOK_HMAC_SECRET
      },
      body: {
        content_id,
        fields: {
          kitsu_task_status_id: new_task_status_id,
          last_kitsu_sync: new Date().toISOString()
        }
      }
    });
  } catch (err) {
    console.error('Failed to sync task status to NocoDB:', err.message);
  }
}

return [{ json: { event_type, handled: true, content_id, task_id, new_task_status_id } }];

// Handle preview-file:new event from Kitsu
// Attach preview URL to content record in NocoDB
const { event_type, data } = $input.first().json;

const preview_file_id = data.preview_file_id || data.id;
const task_id         = data.task_id;
const entity_id       = data.entity_id;
const entity_name     = data.entity_name;

const content_id  = entity_name || entity_id;

// Construct Kitsu preview URL (internal)
const preview_url = preview_file_id
  ? `http://kitsu:80/api/pictures/preview-files/${preview_file_id}/preview`
  : null;

if (content_id && preview_url) {
  try {
    await $http.request({
      method: 'POST',
      url: 'http://localhost:5678/webhook/cf-update-content',
      headers: {
        'Content-Type': 'application/json',
        'x-webhook-secret': $env.N8N_WEBHOOK_HMAC_SECRET
      },
      body: {
        content_id,
        fields: {
          latest_preview_url: preview_url,
          last_kitsu_sync: new Date().toISOString()
        }
      }
    });
  } catch (err) {
    console.error('Failed to attach preview to content:', err.message);
  }
}

return [{ json: { event_type, handled: true, content_id, preview_file_id, preview_url } }];

// Handle comment:new event from Kitsu
// Log for now -- full OpenClaw integration in v2
const { event_type, data } = $input.first().json;

const comment_id  = data.id;
const task_id     = data.task_id;
const text        = data.text || data.comment || '';
const person_id   = data.person_id;
const entity_name = data.entity_name;

// v2: forward to OpenClaw for AI processing
// For now: log only
console.log(`[cf-kitsu-inbound] comment:new on task ${task_id} by ${person_id}: ${text.substring(0, 100)}`);

return [{ json: { event_type, handled: true, comment_id, task_id, note: 'Logged -- OpenClaw integration in v2' } }];
